  "system_time_utc": "The current simulation time in ISO 8601 format.",
  "mount_azimuth": "Current horizontal angle of the telescope in degrees (0-360).",
  "mount_altitude": "Current vertical angle of the telescope in degrees (0-90).",
  "telescope_status": "Current operational mode: IDLE, SLEWING, TRACKING, OBSERVING, or PARKED.",
  "filter_position": "The currently loaded optical filter (e.g., U, B, V, R, I).",
  "dome_shutter_status": "The physical state of the observatory dome: OPEN or CLOSED.",
  "weather_safety_ok": "Internal flag indicating if wind/humidity/rain levels are safe for operation.",
  "remaining_power_pct": "Current battery or system power percentage."
}}
{action_set_definitions}: {
  "get_observatory_status": {
    "description": "Retrieves the current telemetry and operational state of the observatory, including system time, weather safety flag, telescope status, and hardware configuration.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "system_time_utc": "2023-10-27T01:59:00Z",
      "mount_azimuth": 180.0,
      "mount_altitude": 45.0,
      "telescope_status": "IDLE",
      "filter_position": "B",
      "dome_shutter_status": "CLOSED",
      "weather_safety_ok": true,
      "remaining_power_pct": 95.0
    }
  },
  "wait_for_time": {
    "description": "Pauses the agent's execution until the observatory's internal clock reaches the specified UTC timestamp.",
    "parameters": {
      "type": "object",
      "properties": {
        "target_time": {
          "type": "string",
          "description": "The ISO 8601 UTC timestamp to wait for (e.g., '2023-10-27T02:00:00Z')."
        }
      },
      "required": [
        "target_time"
      ]
    },
    "example_output": null
  },
  "set_optical_filter": {
    "description": "Commands the filter wheel to rotate to the specified optical filter.",
    "parameters": {
      "type": "object",
      "properties": {
        "filter_name": {
          "type": "string",
          "enum": [
            "U",
            "B",
            "V",
            "R",
            "I"
          ],
          "description": "The target optical filter."
        }
      },
      "required": [
        "filter_name"
      ]
    },
    "example_output": {
      "status": "success",
      "current_filter": "V"
    }
  },
  "slew_to_target": {
    "description": "Points the telescope mount at the specified celestial coordinates.",
    "parameters": {
      "type": "object",
      "properties": {
        "ra": {
          "type": "string",
          "description": "Right Ascension in 'HHh MMm SSs' format."
        },
        "dec": {
          "type": "string",
          "description": "Declination in '+/-DDd MMm SSs' format."
        }
      },
      "required": [
        "ra",
        "dec"
      ]
    },
    "example_output": {
      "status": "SLEWING"
    }
  },
  "manage_dome_shutter": {
    "description": "Operates the physical dome shutter mechanism of the observatory.",
    "parameters": {
      "type": "object",
      "properties": {
        "action": {
          "type": "string",
          "enum": [
            "OPEN",
            "CLOSED"
          ],
          "description": "Desired state for the dome shutter."
        }
      },
      "required": [
        "action"
      ]
    },
    "example_output": {
      "shutter_state": "OPEN"
    }
  },
  "perform_exposure": {
    "description": "Activates the camera sensor to capture a science-grade image for the specified duration.",
    "parameters": {
      "type": "object",
      "properties": {
        "duration_seconds": {
          "type": "number",
          "description": "The duration of the exposure in seconds."
        }
      },
      "required": [
        "duration_seconds"
      ]
    },
    "example_output": {
      "result": "Exposure complete",
      "file_path": "/data/m42_obs.fits"
    }
  },
  "park_telescope": {
    "description": "Moves the telescope mount to its designated safe storage (PARKED) position.",
    "parameters": {
      "type": "object",
      "properties": {},
      "required": []
    },
    "example_output": {
      "status": "PARKED"
    }
  }
}
